    #[test]
    fn unittest_tile_residues_unmatched_modulo() {
        axes![A = 8];
        let a = <m![A / 4]>::to_value().factorize();
        let b = <m![A % 4]>::to_value().factorize();
        let division = a.clone().divide(b.clone());
        // The divisor `A % 4` is a single term but does not match `A / 4` in
        // the dividend: `tile_residues` therefore reports the unmatched-term
        // failure.
        assert_eq!(division.division_terms.len(), 0);
        assert!(matches!(
            division.tile_residues(2),
            RResult::RErr(DivisionError::DivisorTermCannotDivide)
        ));
    }

    // ── unmatched survivors ─────────────────────────────────────────

    #[test]
    fn unittest_unmatched_term_positions() {
        axes![A = 512, B = 4, C = 8];
        let division = <m![A / 8, B]>::to_value()
            .factorize()
            .divide(<m![B, C]>::to_value().factorize());
        let extents = division.extents().unwrap();
        assert_eq!(extents.dividend.unmatched.len(), 1);
        assert_eq!(
            (
                extents.dividend.unmatched[0].resize,
                extents.dividend.unmatched[0].stride
            ),
            (64, 4)
        );
        assert_eq!(extents.divisor.unmatched.len(), 1);
        assert_eq!(
            (extents.divisor.unmatched[0].resize, extents.divisor.unmatched[0].stride),
            (8, 1)
        );
    }

