        axes![A = 8];
        // m![A # 64] / m![A]: matched chunk takes A (size 8). The outer
        // remainder is pure padding of size 8 — encoded as m![1 # 8], i.e.
        // padding spans the segment's full local size.
        let dividend = <m![A # 64]>::to_value().factorize();
        let divisor = <m![A]>::to_value().factorize();
        let division = dividend.divide(divisor);
