    #[test]
    fn unittest_pure_padding_split_then_mul_round_trips() {
        // m![1 # 64] split at 8 produces two m![1 # 8] pieces (each piece's
        // padding spans its full local size); recombining outer⊗inner via
        // FMapping::mul must normalize back to the original m![1 # 64].
        let original = <m![1 # 64]>::to_value().factorize();
        let Tuple2(outer, inner) = original.split_at(8);
        assert_eq!(inner, <m![1 # 8]>::to_value().factorize());
        assert_eq!(outer, <m![1 # 8]>::to_value().factorize());
        assert_eq!(outer.mul(inner).normalize(), original.clone().normalize());
    }

