    #[test]
    fn unittest_remainder_matched_chunk_cuts_padding_partially() {
        axes![A = 2, B = 3];
        // m![A, B # 8] / m![A, B] with B=3, A=2:
        //   - B is padded to 8 (padding range [3, 8) on dividend side, 5 cells).
        //   - matched B has bounds.min = 4 (smallest divisor of 8 >= 3), so
        //     the removed chunk is [0, 4) — eats B (3) + 1 padding cell.
        //   - leftover padding [4, 8) (4 cells) is what survives.
        //   - matched A removes the outer factor (size 2).
        // After both removals, the leftover is the partial padding tail,
        // compacted via base_stride=4 to a size-2 pure-padding mapping.
        let dividend = <m![A, B # 8]>::to_value().factorize();
        let divisor = <m![A, B]>::to_value().factorize();
        let division = dividend.divide(divisor);
        assert_eq!(
            division.remainder(DivisionSide::Dividend).unwrap(),
            <m![1 # 2]>::to_value().factorize()
        );
    }

    #[test]
    fn unittest_remainder_two_padded_matched_terms_leave_two_padding_tails() {
        axes![A = 3, B = 3];
        // m![A # 8, B # 8] / m![A, B] with A=B=3:
        //   - inner B (in B # 8) matched, leftover padding [3, 8) → 4 cells survive.
        //   - outer A (in A # 8) matched at stride 8, leftover padding [3*8, 8*8) → 4 cells survive.
        //   - remainder concats both leftover padding tails as compacted
        //     pure-padding mapping (each represented as 1 # 2; together 1 # 4).
        let dividend = <m![A # 8, B # 8]>::to_value().factorize();
        let divisor = <m![A, B]>::to_value().factorize();
        let division = dividend.divide(divisor);
        assert_eq!(
            division.remainder(DivisionSide::Dividend).unwrap(),
            <m![1 # 4]>::to_value().factorize()
        );
    }

