    #[test]
    fn unittest_division_unmatched_preserves_original_stride() {
        axes![A = 3, C = 5];
        let dividend = <m![C, A]>::to_value().factorize();
        let divisor = <m![A]>::to_value().factorize();
        let division = dividend.divide(divisor);
        let extents = division.extents().unwrap();

        // `unmatched` carries C with its original stride (3, above the inner A)
        // — unlike `remainder()` which consolidates strides after dropping
        // matched terms.
        assert_eq!(extents.dividend.unmatched.len(), 1);
        assert_eq!(extents.dividend.unmatched[0].stride, 3);
        assert_eq!(extents.dividend.padding_strides, RVec::<Range>::new());

        // `remainder` drops the matched portion and renumbers strides from 1;
        // it should be structurally `m![C]`.
        assert_eq!(
            division.remainder(DivisionSide::Dividend).unwrap(),
            <m![C]>::to_value().factorize()
        );
    }

    #[test]
    fn unittest_slots_outer_to_inner_with_mixed_factors() {
        axes![A = 3, C = 5];
        let dividend = <m![C, A # 16]>::to_value().factorize();
        let divisor = <m![A]>::to_value().factorize();
        let division = dividend.divide(divisor);
        let extents = division.extents().unwrap();

        let [matched] = extents.matched.as_slice() else {
            unreachable!()
        };
        let [unmatched_c] = extents.dividend.unmatched.as_slice() else {
            unreachable!()
        };
        assert_eq!(unmatched_c.stride, 16);

        // Outer-to-inner expected slot order:
        //   unmatched C at stride 16  (outermost)
        //   padding             start 4   (matched-tail [4, 16))
        //   matched A   at stride 1   (extent [1, 4))
        assert_eq!(
            extents.slots(DivisionSide::Dividend),
            vec![
                Slot::Unmatched(unmatched_c.clone()),
                Slot::Padding(Range::new(4, 16)),
                Slot::Matched(matched.clone()),
            ]
        );
    }

