    // ── division: complex padding cases ─────────────────────────────

    #[test]
    fn unittest_division_three_padded_axes_full_match() {
        axes![A = 2, B = 3, C = 5];
        // dividend = m![A # 4, B # 6, C # 8]: each axis carries its own
        // matched-tail padding ([axis.size, resize)) inside its composite.
        // divisor matches all three axes.
        let dividend = <m![A # 4, B # 6, C # 8]>::to_value().factorize();
        let divisor = <m![A, B, C]>::to_value().factorize();
        let division = dividend.divide(divisor);
        let extents = division.extents().unwrap();

        assert_eq!(division.division_terms.len(), 3);
        assert_eq!(extents.dividend.unmatched, RVec::<TermPosition>::new());
        assert_eq!(extents.divisor.unmatched, RVec::<TermPosition>::new());
        // Matched-tail padding per axis on the dividend side, in stride order
        // (inner→outer):
        //   - C # 8 with C=5: bounds.min = smallest_divisor_gte(8, 5) = 8 = max,
        //     so matched chunk swallows the whole [0, 8) — no tail.
        //   - B # 6 with B=3: bounds = {min:3, max:6}, tail [8*3, 8*6) = [24, 48).
        //   - A # 4 with A=2: bounds = {min:2, max:4}, tail [48*2, 48*4) = [96, 192).
        assert_eq!(
            extents.dividend.padding_strides,
            RVec::from(vec![Range::new(24, 48), Range::new(96, 192)])
        );
        // Divisor has no padding (all three axes are unpadded in m![A,B,C]).
        assert_eq!(extents.divisor.padding_strides, RVec::<Range>::new());
    }

    #[test]
    fn unittest_division_three_axes_with_outer_pure_padding() {
        axes![A = 2, B = 3, C = 5];
        // dividend = m![1 # 384, A # 4, B # 6, C # 8]: as previous, plus a
        // pure-padding factor wrapping the whole stack. Note `m![X, Y]` ≡
        // `X.mul(Y)` so `1 # 384` outer scales by the inner cum (192) to a
        // total of 192 * 384 = 73728; its padding range is [192, 73728).
        let dividend = <m![1 # 384, A # 4, B # 6, C # 8]>::to_value().factorize();
        let divisor = <m![A, B, C]>::to_value().factorize();
        let division = dividend.divide(divisor);
        let extents = division.extents().unwrap();

        assert_eq!(division.division_terms.len(), 3);
        // Padding sources: B matched-tail [24, 48), A matched-tail [96, 192),
        // outer pure-pad [192, 73728). Last two touch → merge to [96, 73728).
        assert_eq!(
            extents.dividend.padding_strides,
            RVec::from(vec![Range::new(24, 48), Range::new(96, 73728)])
        );
        assert_eq!(extents.divisor.padding_strides, RVec::<Range>::new());
    }

    #[test]
    fn unittest_division_partial_match_with_unmatched_padded_axis() {
        axes![A = 2, B = 3, C = 5];
        // dividend = m![A # 4, B # 6, C # 8], divisor = m![A, C].
        // B is unmatched (with its own padding around stride 8); A and C
        // are matched, each retaining their matched-tail padding.
        let dividend = <m![A # 4, B # 6, C # 8]>::to_value().factorize();
        let divisor = <m![A, C]>::to_value().factorize();
        let division = dividend.divide(divisor);
        let extents = division.extents().unwrap();

        assert_eq!(division.division_terms.len(), 2);
        // B survives unmatched at its original stride 8. `B # 6` factorizes
        // into Term{B, resize=3} + Padding{size:48} — the unmatched Term keeps
        // resize 3, and the # 6 padding becomes a separate Range.
        let [u_b] = extents.dividend.unmatched.as_slice() else {
            unreachable!()
        };
        assert_eq!((u_b.stride, u_b.resize), (8, 3));

        // Dividend padding: B # 6's outer padding [24, 48) (B unmatched, so
        // its surrounding pad survives), and A's matched-tail [96, 192).
        // C is matched with bounds.min = max = 8, so its [5, 8) pad is
        // swallowed by the matched chunk.
        assert_eq!(
            extents.dividend.padding_strides,
            RVec::from(vec![Range::new(24, 48), Range::new(96, 192)])
        );
        assert_eq!(extents.divisor.padding_strides, RVec::<Range>::new());
    }

    #[test]
    fn unittest_division_three_axes_pure_padding_between_each() {
        axes![A = 2, B = 3, C = 5];
        // Mixed case: composite-resize on each axis AND a pure-padding factor
        // sandwiched between them. Tests interleaving of matched-tail ranges
        // (from # resize) and standalone padding factors.
        // Innermost → outermost: C # 8, then 1 # 16 pure pad above C's region,
        // then B # 6, then 1 # 96 pure pad, then A # 4.
        let dividend = <m![A # 4, 1 # 96, B # 6, 1 # 16, C # 8]>::to_value().factorize();
        let divisor = <m![A, B, C]>::to_value().factorize();
        let division = dividend.divide(divisor);
        let extents = division.extents().unwrap();

        assert_eq!(division.division_terms.len(), 3);
        // Cumulative sizes (m![X, Y] = X.mul(Y), so each `1 # k` scales by
        // the inner cum at its position):
        //   C # 8     → cum 8
        //   1 # 16    → cum 8 * 16 = 128 (range [8, 128))
        //   B # 6     → cum 128 * 6 = 768; B is at stride 128, matched-tail
        //               bounds {min:3, max:6} → [128*3, 128*6) = [384, 768)
        //   1 # 96    → cum 768 * 96 = 73728 (range [768, 73728))
        //   A # 4     → cum 73728 * 4 = 294912; A at stride 73728, matched-tail
        //               bounds {min:2, max:4} → [147456, 294912)
        // C has bounds.min = max = 8 (no tail). B's matched-tail [384, 768)
        // and the 1 # 96 pure pad [768, 73728) touch → merge to [384, 73728).
        assert_eq!(
            extents.dividend.padding_strides,
            RVec::from(vec![
                Range::new(8, 128),
                Range::new(384, 73728),
                Range::new(147456, 294912),
            ])
        );
        assert_eq!(extents.divisor.padding_strides, RVec::<Range>::new());
    }

